# Module: types
# Contains base classes, structs, and enums for the entity system
from interfaces import Describable, Renderable

enum Status:
    PENDING = 0
    ACTIVE = 1
    COMPLETED = 2
    ARCHIVED = 3

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return (self.x ** 2.0 + self.y ** 2.0) ** 0.5

@abstract
class AbstractEntity(Describable):
    """Abstract base class for all entities."""
    id: int
    status: Status

    def __init__(self, id: int):
        self.id = id
        self.status = Status.PENDING

    def get_description(self) -> str:
        return "Abstract entity"

    @virtual
    def get_status_text(self) -> str:
        return "Status: " + str(self.status)

    @abstract
    def process(self) -> bool: ...

class ConcreteEntity(AbstractEntity):
    """A concrete implementation of AbstractEntity."""
    name: str

    def __init__(self, id: int, name: str):
        super().__init__(id)
        self.name = name

    @override
    def get_description(self) -> str:
        return "Entity: " + self.name + " (ID: " + str(self.id) + ")"

    @override
    def get_status_text(self) -> str:
        return self.name + " is " + str(self.status)

    @override
    def process(self) -> bool:
        if self.status == Status.PENDING:
            self.status = Status.ACTIVE
            return True
        return False

class RenderableEntity(ConcreteEntity, Renderable):
    """Entity that is both Describable and Renderable."""
    content: str

    def __init__(self, id: int, name: str, content: str):
        super().__init__(id, name)
        self.content = content

    @override
    def get_description(self) -> str:
        return "Renderable: " + self.name

    @override
    def process(self) -> bool:
        if self.status == Status.PENDING:
            self.status = Status.ACTIVE
            return True
        elif self.status == Status.ACTIVE:
            self.status = Status.COMPLETED
            return True
        return False

    def render(self) -> str:
        return "[" + self.name + "] " + self.content
